/**
 * Core data layer: types, database loading, and basic entity lookups.
 *
 * Reads database.json (generated by scripts/build-data.mjs) which contains
 * pre-transformed typedEntities. Runs at build time / server-component level only.
 *
 * This module is the foundation for all other data modules.
 * Consumers should import from "@/data" (index.ts) for backward compatibility.
 */

import fs from "fs";
import path from "path";
import { loadYaml } from "@lib/yaml";
import { fetchFromWikiServer, withApiFallback, type WithSource } from "@lib/wiki-server";
import {
  TypedEntitySchema,
  type TypedEntity,
  type GenericEntity,
  isRisk,
  isPerson,
  isOrganization,
  isPolicy,
} from "./entity-schemas";
import type { ValidSubcategory } from "./valid-subcategories";

// Re-export for consumers
export type { WithSource };

// database.json is generated here by prebuild
const LOCAL_DATA_DIR = path.resolve(process.cwd(), "src/data");

// Source YAML data lives at the repo root
export const DATA_DIR = path.resolve(process.cwd(), "../../data");

