interface DatabaseShape {
  typedEntities?: Array<Record<string, unknown>>;
  resources: Resource[];
  publications: Publication[];
  experts: Expert[];
  organizations: Organization[];
  cruxes: CruxData[];
  prItems: Record<string, unknown>[];
  backlinks: Record<string, BacklinkEntry[]>;
  relatedGraph: Record<string, RelatedGraphEntry[]>;
  pathRegistry: Record<string, string>;
  idRegistry: IdRegistryMaps;
  pages: Page[];
  /** Page → resource IDs mapping (computed at build time from inline <R>, cited_by, URL matching) */
  pageResources: Record<string, string[]>;
  stats: Record<string, unknown>;
  /** Pre-computed update schedule items (staleness, priority, etc.) */
  updateSchedule?: Array<{
    id: string;
    numericId: string;
    title: string;
    quality: number | null;
    readerImportance: number | null;
    lastUpdated: string | null;
    updateFrequency: number;
    daysSinceUpdate: number;
    daysUntilDue: number;
    staleness: number;
    priority: number;
    category: string;
  }>;
  /** Page reference index: page → { claimReferences, citations } for DB-driven footnotes */
  pageReferenceIndex?: Record<string, SerializedPageReferences>;
  /** Pre-aggregated hallucination risk statistics */
  riskStats?: {
    total: number;
    high: number;
    medium: number;
    low: number;
    avgScore: number;
    topFactors: Array<{ factor: string; count: number }>;
  };
  /** Citation quotes bundled at build time, keyed by pageId */
  citationQuotes?: Record<string, Array<{
    footnote: number;
    url: string | null;
    resourceId: string | null;
    claimText: string;
    sourceQuote: string | null;
    sourceTitle: string | null;
    sourceType: string | null;
    quoteVerified: boolean;
    verificationScore: number | null;
    verifiedAt: string | null;
    accuracyVerdict: string | null;
    accuracyScore: number | null;
    accuracyIssues: string | null;
    accuracySupportingQuotes: string | null;
    verificationDifficulty: string | null;
    accuracyCheckedAt: string | null;
  }>>;
  /**
   * Statement-backed citation dot data bundled at build time, keyed by page slug.
   * Populated by buildStatementCitationDots() from /api/statements/citation-dots/all.
   * Each entry is keyed by footnoteResourceId (e.g. "cr-abc123") and must be mapped
   * to a numeric footnote number via the referenceMap from renderMdxPage().
   */
  statementCitationDots?: Record<string, Array<{
    footnoteResourceId: string;
    claimText: string;
    url: string | null;
    resourceId: string | null;
    sourceQuote: string | null;
    sourceTitle: string | null;
    sourceType: string | null;
    quoteVerified: boolean;
    accuracyVerdict: string | null;
    accuracyScore: number | null;
    accuracyIssues: string | null;
    accuracyCheckedAt: string | null;
  }>>;
  /** KB (Knowledge Base) structured entity data from packages/kb */
  kb?: import("@longterm-wiki/kb").SerializedKB;
  /** KB fact verification status: factId → verdict (from citation quotes cross-reference) */
  kbFactVerification?: Record<string, string>;
}

// ============================================================================
// DATABASE LOADING
// ============================================================================

/** Union of fully-typed entities and generic (unknown-type) entities */
export type AnyEntity = TypedEntity | GenericEntity;

let _database: DatabaseShape | null = null;
let _typedEntities: AnyEntity[] | null = null;

export function getDatabase(): DatabaseShape {
  if (_database) return _database;

  const dbPath = path.join(LOCAL_DATA_DIR, "database.json");

  try {
    const raw = fs.readFileSync(dbPath, "utf-8");
    _database = JSON.parse(raw) as DatabaseShape;
  } catch (err) {
    throw new Error(
      `Failed to load database from ${dbPath}: ${err instanceof Error ? err.message : err}. ` +
      `Run "pnpm prebuild" first.`
    );
  }
  return _database;
}

/** Get all typed entities from the database */
export function getTypedEntities(): AnyEntity[] {
  if (_typedEntities) return _typedEntities;

  const db = getDatabase();

  if (!db.typedEntities || db.typedEntities.length === 0) {
    throw new Error(
      'database.json is missing typedEntities. ' +
      'Run "pnpm --filter longterm-next prebuild" to rebuild.'
    );
  }

  const entities: AnyEntity[] = [];
  const isDev = process.env.NODE_ENV === "development";

  for (const raw of db.typedEntities) {
    const result = TypedEntitySchema.safeParse(raw);
    if (result.success) {
      entities.push(result.data);
    } else {
      // Unknown entity types — keep all fields as-is.
      // Don't re-parse through GenericEntitySchema as Zod would strip extra keys
      // like content, currentAssessment, ratings, causeEffectGraph.
      if (isDev) {
        const id = (raw as Record<string, unknown>).id;
        const type = (raw as Record<string, unknown>).entityType as string;
        console.warn(
          `[entity-validation] ${id} (${type}): ${result.error.issues.map(i => i.message).join(", ")}`
        );
      }
      entities.push(raw as unknown as GenericEntity);
    }
  }

  _typedEntities = entities;
  return _typedEntities;
}

